if (exec) { 
try { str = await eval(str); if (typeof str !== 'string') str = (JSON.stringify(str, null, '\t') == '{}') ? util.inspect(str) : JSON.stringify(str, null, '\t') } catch { str = trim ? str.trim() : str }; } else { str = trim ? str.trim() : str };
const res = await kaoruko.sendMessage(id, {text: str, ...options}, {quoted: quoted});
