/* ─── Upload de mídia ─── */
async function uploadMidia(origem, nomeArquivo = 'media.jpg') {
  try {
const buffer = Buffer.isBuffer(origem) ? origem : await getBuffer(origem);
const form = new FormData();
form.append('apikey', API_KEY_WAGURI);
form.append('media', buffer, { filename: nomeArquivo, contentType: 'image/jpeg' });
const res = await axios.post(`${okarunsite}/api/upload`, form, {
headers: form.getHeaders(),
maxBodyLength: Infinity
});
if (res.data?.status && res.data?.resultado) return res.data.resultado;
throw new Error('Upload falhou: ' + JSON.stringify(res.data));
  } catch (e) {
errorLog('[uploadMidia] ' + e.message);
return null;
  }
}

async function getFoto(sender, kaoruko) {
  try {
const pfp = await kaoruko.profilePictureUrl(sender, 'image').catch(() => null)
if (!pfp) return links.semfoto

const buffer = await getBuffer(pfp).catch(() => null)
if (!buffer) return links.semfoto

const uploaded = await uploadMidia(buffer, 'pfp.jpg')
return uploaded || links.semfoto
  } catch {
return links.semfoto
  }
}


