const sendAudio = async (id, link, tipo = 'url', quoted = info) => {
const inicio = Date.now();
console.log(`\nPreparando áudio para ${id}`);

const recordingInterval = setInterval(async () => {
try { await client.sendPresenceUpdate('recording', id); } catch {}
}, 8000);

try {
await client.sendPresenceUpdate('recording', id);

const oggPath = await converterogg(id, link, tipo);
const buffer = fs.readFileSync(oggPath);

await client.sendMessage(id, {
audio: buffer,
mimetype: 'audio/ogg; codecs=opus',
ptt: true,
waveform: [0, 30, 70, 100, 70, 30, 0]
}, { quoted: info });

await unlink(oggPath).catch(() => {});

const tempo = ((Date.now() - inicio) / 1000).toFixed(1);
console.log(`Áudio enviado em ${tempo}s`);
return true;

} catch (e) {
console.log('Erro no envio:', e.message);
await client.sendMessage(id, { text: '❌ Áudio falhou. Tenta de novo.' });
return false;

} finally {
clearInterval(recordingInterval);
await client.sendPresenceUpdate('paused', id).catch(() => {});
await client.sendPresenceUpdate('available', id).catch(() => {});
}
};

function formatarDataSimples(ts) {
if (!ts) return "Desconhecido";
const n = Number(ts);
if (Number.isNaN(n)) return "Desconhecido";
const time = n > 1e12 ? n : n * 1000; // trata segundos ou milissegundos
const d = new Date(time);
if (isNaN(d.getTime())) return "Desconhecido";

const dia = String(d.getDate()).padStart(2, "0");
const mes = String(d.getMonth() + 1).padStart(2, "0");
const ano = d.getFullYear();
return `${dia}/${mes}/${ano}`;
}

function formatarData(ts) {
if (!ts) return "Desconhecido";
const n = Number(ts);
if (Number.isNaN(n)) return "Desconhecido";
const time = n > 1e12 ? n : n * 1000;
const d = new Date(time);
if (isNaN(d.getTime())) return "Desconhecido";

const dia = String(d.getDate()).padStart(2, "0");
const mes = String(d.getMonth() + 1).padStart(2, "0");
const ano = d.getFullYear();
const h = String(d.getHours()).padStart(2, "0");
const m = String(d.getMinutes()).padStart(2, "0");
const s = String(d.getSeconds()).padStart(2, "0");
return `${dia}/${mes}/${ano} — ${h}:${m}:${s}`;
}



const dbDir = path.join(__dirname, "database");
const dbPath = path.join(dbDir, "member_tags.json");

let memberTagsCache = [];

try {
if (!fs.existsSync(dbDir)) fs.mkdirSync(dbDir, { recursive: true });
if (fs.existsSync(dbPath)) {
memberTagsCache = JSON.parse(fs.readFileSync(dbPath, "utf-8")).memberTags || [];
} else {
fs.writeFileSync(dbPath, JSON.stringify({ memberTags: [] }));
}
} catch (e) {
console.error("[TAGS_DB] Erro:", e.message);
}

const msg = info?.message;
const prot = msg?.protocolMessage;

if (prot?.type === 30 && prot.memberLabel?.label) {
const part = info.key.participant || info.key.remoteJid || "";
const from = info.key.remoteJid || "";
const newL = prot.memberLabel.label;

if (from?.endsWith("@g.us") && part) {
const idx = memberTagsCache.findIndex(t => t.g === from && t.p === part);
const existing = idx >= 0 ? memberTagsCache[idx] : null;

if (existing && existing.l === newL) return;

const nTag = { g: from, p: part, l: newL, u: Date.now() };
if (idx >= 0) memberTagsCache[idx] = nTag; else memberTagsCache.push(nTag);

try {
fs.writeFileSync(dbPath, JSON.stringify({ memberTags: memberTagsCache }));
if (typeof infoLog === "function") infoLog(`Tag "${newL}" -> ${part}`);

kaoruko.sendMessage(from, {
text: `🏷️ *TAG ATUALIZADA*\n👤 ${info.pushname || "Usuário"}\n🆔 @${part.split("@")[0]}\n📌 *${newL}*`,
mentions: [part]
});
} catch (e) {
console.error("[TAGS_DB] Erro ao salvar:", e.message);
}
}
}


const permuteNumberEmoji = (nmr) => {
nt = String(nmr)
nv = ``
for(i of nt) {
if(Number(i) == 0) np = `0️⃣`
if(Number(i) == 1) np = `1️⃣`
if(Number(i) == 2) np = `2️⃣`
if(Number(i) == 3) np = `3️⃣`
if(Number(i) == 4) np = `4️⃣`
if(Number(i) == 5) np = `5️⃣`
if(Number(i) == 6) np = `6️⃣`
if(Number(i) == 7) np = `7️⃣`
if(Number(i) == 8) np = `8️⃣`
if(Number(i) == 9) np = `9️⃣`
nv += np
}
return nv
}




async function _sendCardImg(dest, cardJSON, caption, quoted) {
const buf = getCardBuffer(cardJSON);
if (!buf) return;
try {
await kaoruko.sendMessage(dest, {
image: buf,
caption: caption || '',
}, quoted ? { quoted } : {});
} catch (e) {
console.error('[UNO-IMG]', e.message);
}
}

async function _sendHandImg(dest, hand) {
if (!hand?.length) return;
try {
const media = [];
for (let i = 0; i < hand.length; i++) {
const buf = getCardBuffer(hand[i]);
if (!buf) continue;
media.push({ image: buf, caption: `[${i + 1}] ${hand[i].display || ''}` });
}
if (!media.length) return;

if (media.length === 1) {
await kaoruko.sendMessage(dest, {
image: media[0].image,
caption: media[0].caption,
});
} else {
await kaoruko.sendMessage(dest, {
album: media,
caption: `🖐️ Suas cartas (${media.length}):`,
});
}
} catch (e) {
console.error('[UNO-HAND-IMG]', e.message);
}
}

/* ── UNO: jogar sem prefixo ───────────────────────────────────────────────
 Detecta mensagens como "carta 3", "carta 7 Vermelho" no grupo e processa
 como se o jogador tivesse usado !jogar — só age se for a vez dele.*/
async function _handleUnoNatural() {
if (!isGroup) return;

const sessNat = _uno.sessions?.get(from);
if (!sessNat || sessNat.status !== 'playing') return;

/* Regex: "carta N" ou "carta N cor" — case-insensitive, sem prefixo */
const match = (budy || '').trim().match(
/^carta\s+(\d+)(?:\s+(vermelho|azul|verde|amarelo))?$/i
);
if (!match) return;

const cardNum = parseInt(match[1]);
const chosenColor = match[2]
? match[2].charAt(0).toUpperCase() + match[2].slice(1).toLowerCase()
: null;

/* Só age se é a vez do sender */
const pmNat = sessNat.playerMap.find(p => p.userId === sender);
if (!pmNat) return;

const engine = _uno._engine(from);
if (!engine) return;
const stateNat = engine.getState();
if (stateNat.currentPlayer !== pmNat.name) return;

reagir(from, '⏳');
const res = await _uno.playCard(from, sender, cardNum, chosenColor);

if (res.erro) return reply(res.erro);

if (res.vitoria) {
reagir(from, '🏆');
return await kaoruko.sendMessage(from, {
text:
`🏆 *『 U N O — FIM DE JOGO 』*\n—\n` +
`🎉 *${res.winner}* VENCEU A PARTIDA! 🎊`,
}, { quoted: waguriselo });
}

let msgNat =
`*『 🃏 U N O 』*\n—\n` +
`✅ *${pushname}* jogou a carta *${cardNum}*!\n` +
`🃏 Topo: *${res.topCard || '?'}*\n` +
`🔄 Vez de: *${res.nextPlayer || '?'}*\n` +
`—\n📊 ${res.scoreboard || ''}`;
if (res.unoWarning) msgNat += `\n⚠️ ${res.unoWarning}`;

await kaoruko.sendMessage(from, { text: msgNat }, { quoted: waguriselo });

// topBuf é um Buffer direto retornado pela engine
if (res.topBuf) {
try {
await kaoruko.sendMessage(from, {
image: res.topBuf,
caption: `🃏 Topo: *${res.topCard || '?'}*`,
}, { quoted: waguriselo });
} catch (_) {}
}

await new Promise(r => setTimeout(r, 900));
await _uno.processAITurns(from);

if (_uno.sessions?.get(from)?.status === 'playing') {
await _enviarMaoPV(from, res.nextPlayer, res.topCard);
}
}

/* Envia mão para todos os jogadores humanos do channelId (grupo) */
async function _enviarMaoTodos(channelId, firstPlayer, topCard) {
const session = _uno.sessions?.get(channelId);
if (!session) return;
const engine = _uno._engine(channelId);
if (!engine) return;
const state = engine.getState();

for (const pm of session.playerMap) {
if (pm.isBot) continue;
const pInfo = state.players.find(p => p.name === pm.name);
if (!pInfo?.hand?.length) continue;

const ehVez= firstPlayer === pm.name;
const jogaveis = pInfo.validMoves?.length
? `✅ Jogáveis: *${pInfo.validMoves.map(v => v + 1).join(', ')}*`
: '';

try {
await kaoruko.sendMessage(pm.userId, {
text:
`*『 🖐️ SUA MÃO — UNO 』*\n—\n` +
`🃏 Topo: *${topCard || '?'}*\n` +
`${ehVez ? '▶️ *VOCÊ COMEÇA!*' : '⏳ Aguarde sua vez.'}\n` +
`🎯 Cartas: *${pInfo.cardsInHand ?? pInfo.hand.length}*\n` +
`${jogaveis}\n` +
`—\nDigite *${prefix}jogar [nº]* no grupo para jogar.`,
});
await _sendHandImg(pm.userId, pInfo.hand);
} catch (e) {
console.error('[UNO-MAO-TODOS]', e.message);
}
}
}

/* Envia mão para um jogador específico (por nome) via PV */
async function _enviarMaoPV(channelId, nomeJogador, topCard) {
if (!nomeJogador) return;
const session = _uno.sessions?.get(channelId);
if (!session) return;

const pm = session.playerMap.find(
p => (p.name || '').toLowerCase() === (nomeJogador || '').toLowerCase()
);
if (!pm || pm.isBot) return;

const engine = _uno._engine(channelId);
if (!engine) return;
const state = engine.getState();
const pInfo = state.players.find(p => p.name === pm.name);
if (!pInfo?.hand?.length) return;

const ehVez= state.currentPlayer === pm.name;
const jogaveis = pInfo.validMoves?.length
? `✅ Jogáveis: *${pInfo.validMoves.map(v => v + 1).join(', ')}*`
: '';

try {
await kaoruko.sendMessage(pm.userId, {
text:
`*『 🖐️ SUA MÃO — UNO 』*\n—\n` +
`🃏 Topo: *${topCard || state.topCard?.display || '?'}*\n` +
`${ehVez ? '▶️ *É SUA VEZ!*' : '⏳ Aguarde sua vez.'}\n` +
`🎯 Cartas: *${pInfo.cardsInHand ?? pInfo.hand.length}*\n` +
`${jogaveis}\n` +
`—\nDigite *${prefix}jogar [nº]* no grupo.`,
});
await _sendHandImg(pm.userId, pInfo.hand);
} catch (e) {
console.error('[UNO-PV]', e.message);
}
}

