/* EVAL SIMPLES: > código */
if (body.startsWith('>')) {
if (info.key.fromMe) return
if (!SoDono && !isnit && !issupre && !ischyt) return
try {
const result = JSON.stringify(eval(body.slice(2)), null, '\t') ?? 'undefined'
return sendCode(from, 'Eval Result', result, 'javascript', '> avaliado com sucesso')
} catch (e) {
return sendCode(from, '❌ Erro', String(e), 'javascript')
}
}

/* EVAL ASYNC COM INSPECT: ? código */
if (body.startsWith('?')) {
if (!SoDono && !isnit) return
const code = body.trim().slice(1)
let result
try {
result = await Promise.race([
eval(`(async () => { const res = ${code}; return (res instanceof Promise) ? await res : res })()`),
new Promise((_, rej) => setTimeout(() => rej(new Error('Timeout: 10s excedido')), 10_000))
])
} catch (e) {
return sendCode(from, '❌ Erro no Eval', String(e), 'javascript')
}

if (result !== undefined) {
const util = require('util')
const output = util.inspect(result, { depth: null, showHidden: true, colors: false, getters: true })

/* Se for objeto/array, tenta mandar como richResponse com blocos separados */
if (typeof result === 'object' && result !== null && !Array.isArray(result)) {
try {
const entries = Object.entries(result).slice(0, 20) /* limite de segurança */
const rows = [['Chave', 'Valor'], ...entries.map(([k, v]) => [k, String(v)])]
return sendTable(from, 'Resultado', rows, '? Eval Output', `${entries.length} propriedades`)
} catch { /* fallback abaixo */ }
}

if (Array.isArray(result)) {
try {
const rows = [['Index', 'Valor'], ...result.slice(0, 20).map((v, i) => [String(i), String(v)])]
return sendTable(from, 'Resultado', rows, '? Eval Output', `${result.length} itens`)
} catch { /* fallback abaixo */ }
}

// fallback: code block
const chunks = output.match(/.{1,3800}/gs) ?? ['(vazio)']
for (const chunk of chunks) {
await sendCode(from, '? Eval Output', chunk, 'javascript')
}
} else {
return reply('✅ *undefined*')
}
}

