// ─── SHELL EXEC: $ comando ────────────────────────────────────────────────────
if (body.startsWith('$') && !body.startsWith('$$')) {
if (info.key.fromMe) return
if (!SoDono && !isnit) return
const cmd = q.trim()
if (!cmd) return reply('⚠️ Nenhum comando fornecido.')
exec(cmd, { timeout: 15_000, maxBuffer: 1024 * 512 }, (err, stdout, stderr) => {
const out = stdout?.trim()
const errOut = stderr?.trim()
if (err && !out) return sendCode(from, '❌ Shell Error', errOut || String(err), 'bash')
const full = [out, errOut ? `// stderr:\n${errOut}` : ''].filter(Boolean).join('\n\n')
const chunks = full.match(/.{1,3800}/gs) ?? ['(sem output)']
chunks.forEach(chunk => sendCode(from, `$ ${cmd}`, chunk, 'bash'))
})
}

// ─── SHELL INTERATIVO: $$ comando ────────────────────────────────────────────
if (body.startsWith('$$')) {
if (info.key.fromMe) return
if (!SoDono) return
const cmd = body.slice(3).trim()
if (!cmd) return reply('⚠️ Nenhum comando fornecido.')
reply('⏳ Executando...')
exec(cmd, { timeout: 60_000, maxBuffer: 1024 * 1024 }, (err, stdout, stderr) => {
const out = stdout?.trim()
const errOut = stderr?.trim()
if (err && !out) return sendCode(from, '❌ Shell Error', errOut || String(err), 'bash')
const full = [out, errOut ? `// stderr:\n${errOut}` : ''].filter(Boolean).join('\n\n')
const chunks = full.match(/.{1,3800}/gs) ?? ['(sem output)']
chunks.forEach(chunk => sendCode(from, `$$ ${cmd}`, chunk, 'bash'))
})
}

