// ─── Upload com fallback: Catbox (permanente) → Pixeldrain (60d sem acesso) ───
// By: Eduh Dev

async function uploadCatbox(buffer, filename, { retries = 3, timeoutMs = 60000 } = {}) {
const sleep = ms => new Promise(r => setTimeout(r, ms))
let lastError

for (let attempt = 1; attempt <= retries; attempt++) {
try {
const FormData = require('form-data')
const form = new FormData()
form.append('reqtype', 'fileupload')
form.append('fileToUpload', buffer, { filename })

const res = await axios.post('https://catbox.moe/user/api.php', form, {
headers: form.getHeaders(),
timeout: timeoutMs,
maxBodyLength: Infinity,
maxContentLength: Infinity,
})

const text = (res.data || '').trim()
if (!text.startsWith('http')) throw new Error(`Resposta inválida: ${text}`)

console.log(`✅ [Catbox] Upload ok: ${text}`)
return text

} catch (e) {
lastError = e
console.warn(`⚠️ [Catbox] Tentativa ${attempt}/${retries} falhou: ${e.message}`)
if (attempt < retries) await sleep(2000 * attempt)
}
}

// Fallback: Pixeldrain (expira se ficar 60 dias sem nenhum download)
console.warn('⚠️ [Catbox] Todas tentativas falharam, tentando Pixeldrain...')
return await uploadPixeldrain(buffer, filename)
}

async function uploadPixeldrain(buffer, filename, timeoutMs = 60000) {
const res = await axios.put(
`https://pixeldrain.com/api/file/${encodeURIComponent(filename)}`,
buffer,
{
headers: {
'Content-Type': 'application/octet-stream',
'Content-Length': buffer.length,
},
timeout: timeoutMs,
maxBodyLength: Infinity,
maxContentLength: Infinity,
}
)

if (!res.data?.id) throw new Error('Pixeldrain sem ID na resposta')
const url = `https://pixeldrain.com/api/file/${res.data.id}?download`
console.log(`✅ [Pixeldrain] Upload ok: ${url}`)
return url
}


