async function atualizarDbGrupos(reset = false) {
// Lê o JSON completo do arquivo antes de modificar
const nescJson = JSON.parse(fs.readFileSync(configpath, 'utf-8'))
nescJson.dbgp = sendHours('HH')
fs.writeFileSync(configpath, JSON.stringify(nescJson, null, 2) + '\n')

let dbgp = sendHours('HH')

let allgp = Object.values(await kaoruko.groupFetchAllParticipating())
.sort((a, b) => a.subject?.localeCompare(b.subject))

saveJSON(allgp, './util/temp/grupos.json')
infoLog(colors.green(`LISTA DE ${allgp.length} GRUPOS ATUALIZADA COM SUCESSO ÀS ${sendHours('HH:mm')}`))

let allGroups = []
if (fs.existsSync('./util/temp/grupos.json')) {
try { allGroups = JSON.parse(fs.readFileSync('./util/temp/grupos.json', 'utf-8')) } catch {}
}

let deletegp = allGroups.filter(a => !allgp.some(b => b.id === a.id))
if (deletegp.length > 0) {
successLog(colors.red('ESTOU REMOVENDO JSON DOS GRUPOS QUE O BOT NÃO SE ENCONTRA MAIS EDUH:'));
infoLog(colors.white('\n' + deletegp.map(d => `- ./database/grupos/activation_gp/${d.id}.json (${d.subject})`).join('\n'))
)
deletegp.forEach(d => {
if (fs.existsSync(`./database/grupos/activation_gp/${d.id}.json`)) {
fs.unlinkSync(`./database/grupos/activation_gp/${d.id}.json`)
}
})
}

if (reset) {
setTimeout(() => process.exit(), 2000)
}
}

if (isGroup && Number(dbgp) !== Number(sendHours('HH'))) {
atualizarDbGrupos(true)
}


