if(Number(gth.split(":")[1]) !== 0) {
// Fix: arredonda para HH:00 do horário atual do anúncio, não da hora do sistema
soma = `${gth.split(":")[0]}:00`
groupAds[AB].tempo.horario = soma
saveADS()
return reply(`O anúncio de ID ${q} teve seu horário alterado de *${gth}* para *${soma}* ⏲`)
} else return reply(`Este anúncio já tem seus minutos em 00`)
break

