async function getUser(num) {
const jid = `${num}@s.whatsapp.net`;
let pp = links.semfoto;
let bio = "Sem bio";

try {
  pp = await kaoruko.profilePictureUrl(jid, "image").catch(() => links.semfoto);
} catch (err) {
  console.error("Erro ao obter foto:", err);
}

try {
  const sts = await kaoruko.fetchStatus(jid);
  console.log("Resposta fetchStatus:", sts);

  if (Array.isArray(sts)) {
bio = sts[0]?.status?.status?.trim() || "Privada";
  } else if (sts?.status) {
bio = sts.status.trim() || "Privada";
  } else {
bio = "Privada";
  }

  if (!bio) bio = "Sem bio";
  if (bio.length > 180) bio = bio.slice(0, 90) + "...";
} catch (err) {
  console.error("Erro ao obter bio:", err);
  bio = "Privada";
}

return { pp, bio };
}

