if (!global.zipProcess) {//By:<\> 𝑷𝒂𝒖𝒍𝒐 𝑴𝒐𝒅𝒔 ᴶˢ
global.zipProcess = {
zipFilePath: null,
executionCount: 0
}
}
global.zipProcess.executionCount++
const inputArg = args.join(' ')
if (global.zipProcess.executionCount === 1) {
console.log(`Iniciando o processo de zipagem de: ${inputArg}`)
try {
const zipTarget = async () => {
const outputFilePath = `${inputArg}.zip`
console.log(`Iniciando a zipagem em: ${inputArg}`)
return new Promise((resolve, reject) => {
const output = fs.createWriteStream(outputFilePath)
const archive = archiver('zip', {
zlib: { level: 9 }
})
output.on('close', () => {
console.log(`Arquivo zip criado com sucesso: ${archive.pointer()} bytes`)
resolve(outputFilePath)
})
archive.on('error', (err) => {
console.error('Erro ao criar o arquivo zip:', err)
reject(err)
})
archive.pipe(output)
if (fs.existsSync(inputArg)) {
if (fs.lstatSync(inputArg).isDirectory()) {
archive.directory(inputArg + '/', path.basename(inputArg))
} else if (fs.lstatSync(inputArg).isFile()) {
archive.file(inputArg, { name: path.basename(inputArg) })
} else {
console.log('Caminho fornecido não é válido.')
return reject(new Error('Caminho fornecido não é válido.'))
}
} else {
console.log('Caminho fornecido não existe.')
return reject(new Error('Caminho fornecido não existe.'))
}
archive.finalize()
})
}
console.log('Iniciando a compactação...')
global.zipProcess.zipFilePath = await zipTarget()
console.log(`Pasta ou arquivo zipado com sucesso! Caminho do arquivo zip: ${global.zipProcess.zipFilePath}`)
reply('Arquivo zipado com sucesso! Agora você pode enviar o arquivo.')
} catch (err) {
console.error('Erro durante o processo de zipagem:', err)
reply('Ocorreu um erro ao zipar o arquivo.')
}
} else if (global.zipProcess.executionCount === 2) {
const recipient = inputArg
if (!global.zipProcess.zipFilePath || !fs.existsSync(global.zipProcess.zipFilePath)) {
return reply('Arquivo zip não encontrado. Tente zipar novamente.')
}
let chatId
if (recipient.startsWith('+')) {
chatId = `${recipient.replace(/\D/g, '')}@c.us`
} else {
return reply('Por favor, forneça um número de telefone válido.')
}
console.log(`Enviando arquivo para o destinatário: ${chatId}`)
try {
await kaoruko.sendMessage(chatId, { document: { url: global.zipProcess.zipFilePath }, caption: `${tempo} meu dono ${ownerName} me mandou te 
enviar esse arquivo 📁 `, mimetype: 'application/zip', fileName: path.basename(global.zipProcess.zipFilePath), contextInfo: { mentionedJid: [sender], externalAdReply: { showAdAttribution: true, mediaType: 1, mediaUrl: null, title: `💞 ${NomeDoBot} 💞\n》🅒🅛🅘🅠🅤🅔 🅐🅠🅤🅘《`, body: null, sourceUrl: links.linkss, mediaUrl: 'https://youtube.com/@Otaku.mp4', thumbnail: await getBuffer(links.linksimg.menu)}}}, {quoted: waguriselo})
console.log('Arquivo enviado com sucesso!')
fs.unlinkSync(global.zipProcess.zipFilePath)
console.log('Arquivo zip deletado após o envio.')
global.zipProcess.zipFilePath = null
global.zipProcess.executionCount = 0
reply(`Arquivo zip enviado com sucesso para: ${recipient}`)
} catch (error) {
console.error('Erro ao reply o arquivo:', error)
reply('Ocorreu um erro ao enviar o arquivo.')
}
} else {
global.zipProcess.zipFilePath = null
global.zipProcess.executionCount = 0
reply('Comando executado com sucesso, mas excedeu o limite de uso. Por favor, inicie novamente com *zip*.')
}
