function calcularPrazoEmMilissegundos(prazo) {
const regex = /(\d+)([smhd])/g
let match
let totalMilliseconds = 0
while ((match = regex.exec(prazo)) !== null) {
const valor = parseInt(match[1])
const unidade = match[2]
switch (unidade) {
case 's':
totalMilliseconds += valor * 1000
break
case 'm':
totalMilliseconds += valor * 60 * 1000
break
case 'h':
totalMilliseconds += valor * 60 * 60 * 1000
break
case 'd':
totalMilliseconds += valor * 24 * 60 * 60 * 1000
break
}
}
return totalMilliseconds
}
