if (!isQuotedAudio) return reply("Hm~ preciso que você mencione um áudio pra eu conseguir transcrever. 🌸")
const quotedAudioMessage = info.message.extendedTextMessage.contextInfo.quotedMessage
const receivedAudioMessage = quotedAudioMessage.audioMessage
if (receivedAudioMessage.fileLength > 10900000) {
return reply("Esse áudio é grande demais... Só consigo transcrever até *2MB*, tá? Manda um menor~ 😅")
}
const isVoiceNote = receivedAudioMessage.ptt ? true : false
const detectedAudioType = isVoiceNote ? 'Áudio de voz' : 'Arquivo de áudio'
console.log(`[INFO] Tipo de áudio detectado: ${detectedAudioType}`)
let messageToEdit
let emojiIntervalId
let tempAudioFilePath
try {//By:Eduh Dev </> 🪐
console.log('[INFO] Iniciando processo de transcrição...')
messageToEdit = await kaoruko.sendMessage(from, { text: `✍🏽 _Deixa eu ouvir com atenção... aguarda um segundo~_ 🕛` }, { quoted: info })
const emojiSequence = ['🕛', '🕐', '🕑', '🕒', '🕓', '🕔', '🕕', '🕖', '🕗', '🕘', '🕙', '🕚', '🕛']
let emojiIndex = 0
async function updateEmoji() {
await kaoruko.sendMessage(from, { text: `✍🏽 _Deixa eu ouvir com atenção... aguarda um segundo~ ${emojiSequence[emojiIndex]}_`, edit: messageToEdit.key }, { quoted: info })
emojiIndex = (emojiIndex + 1) % emojiSequence.length
}
emojiIntervalId = setInterval(updateEmoji, 2000)
console.log('[INFO] Baixando o conteúdo do áudio...')
const downloadedAudioData = await downloadContentFromMessage(receivedAudioMessage, 'audio')
let audioBufferChunks = []
for await (const audioChunk of downloadedAudioData) {
audioBufferChunks.push(audioChunk)
}
const completeAudioBuffer = Buffer.concat(audioBufferChunks)
tempAudioFilePath = `./database/data/media/audios/totext/totext-${sender}.mp3`
console.log(`[INFO] Salvando o áudio em: ${tempAudioFilePath}`)
fs.writeFileSync(tempAudioFilePath, completeAudioBuffer)
console.log('[INFO] Fazendo upload do áudio para API...')
const uploadResponse = await axios.post('https://api.assemblyai.com/v2/upload', completeAudioBuffer, {
headers: {
'authorization': `${API_KEY_ASSEMBLY}`,
'content-type': 'application/octet-stream'
}
})
const audioUploadUrl = uploadResponse.data.upload_url
console.log('[INFO] Áudio enviado com sucesso, URL:', audioUploadUrl)
console.log('[INFO] Solicitando transcrição...')
const transcriptResponse = await axios.post('https://api.assemblyai.com/v2/transcript', {
audio_url: audioUploadUrl,
language_detection: true,
speech_models: ['universal-2']
}, {
headers: {
'authorization': `${API_KEY_ASSEMBLY}`,
'content-type': 'application/json'
}
})
const transcriptIdReceived = transcriptResponse.data.id
console.log(`[INFO] ID da transcrição recebida: ${transcriptIdReceived}`)
let transcriptResultData
while (true) {
console.log('[INFO] Verificando status da transcrição...')
const statusCheckResponse = await axios.get(`https://api.assemblyai.com/v2/transcript/${transcriptIdReceived}`, {
headers: { 'authorization': `${API_KEY_ASSEMBLY}` }
})
transcriptResultData = statusCheckResponse.data
console.log(`[INFO] Status da transcrição: ${transcriptResultData.status}`)
if (transcriptResultData.status === 'completed') {
break
}
if (transcriptResultData.status === 'error') {
throw new Error(`A transcrição falhou: ${transcriptResultData.error}`)
}
await new Promise(resolve => setTimeout(resolve, 3000))
}
clearInterval(emojiIntervalId)
if (transcriptResultData.text) {
console.log('[INFO] Transcrição concluída com sucesso.')
await kaoruko.sendMessage(from, { text: `🌸 _Pronto, consegui transcrever tudo~_ ✨\n\n${transcriptResultData.text}`, edit: messageToEdit.key }, { quoted: info })
} else {
throw new Error("Não encontrei nenhum texto no áudio.")
}
console.log(`[INFO] Excluindo o arquivo temporário: ${tempAudioFilePath}`)
fs.unlinkSync(tempAudioFilePath)
} catch (error) {
console.error("[ERRO] Erro ao transcrever o áudio:", error)
clearInterval(emojiIntervalId)
if (messageToEdit) {
await kaoruko.sendMessage(from, { text: `Ah... não consegui transcrever esse áudio. 😔\n_Erro: ${error.message}_`, edit: messageToEdit.key }, { quoted: info })
} else {
reply("Algo deu errado aqui... Tenta de novo daqui a pouco? 🌸")
}
if (fs.existsSync(tempAudioFilePath)) {
console.log(`[INFO] Excluindo o arquivo temporário devido a erro: ${tempAudioFilePath}`)
fs.unlinkSync(tempAudioFilePath)
}
}
break


