try {
const fullArg = args.join(' ')
const pipeidx = fullArg.indexOf('|')
const caseName = (pipeidx !== -1 ? fullArg.slice(0, pipeidx) : fullArg).trim()
const destRaw= pipeidx !== -1 ? fullArg.slice(pipeidx + 1).trim() : null

let targetJid
if (!destRaw) {
targetJid = from
} else if (destRaw.includes('@')) {
const lidNum = destRaw.replace('@', '').trim()
const lidJid = lidNum + (lidNum.length > 13 ? '@lid' : '@s.whatsapp.net')
targetJid = convertWhatsAppUser(lidJid)
} else {
const numLimpo = destRaw.replace(/\D/g, '')
targetJid = numLimpo + '@s.whatsapp.net'
}

const isPv = targetJid !== from
const numExibir = targetJid.split('@')[0]

await reply(
isPv
? `Seu pedido é uma ordem! Enviando a case *"${caseName}"* para @${numExibir}... 🌸`
: `Seu pedido é uma ordem! Aguarde um pouco mestre! Buscando a case *"${caseName}"*... 🌸`,
{ mentions: isPv ? [targetJid] : [] }
)
await sleep(500)

const source = fs.readFileSync('./index.js').toString()
const caseStart = `case '${caseName}'`
const startIdx = source.indexOf(caseStart)

if (startIdx === -1) {
return sendRich(targetJid, [
{ text: `❌ Case não encontrada: *${caseName}*` },
{ text: 'Verifique se o nome está correto e tente novamente.' }
])
}

const slice = source.slice(startIdx)
let depth = 0
let endIdx = slice.length
for (let i = 0; i < slice.length; i++) {
if (slice[i] === '{') depth++
if (slice[i] === '}') depth--
if (depth === 0 && slice.slice(i, i + 5) === 'break') {
endIdx = i + 5
break
}
}

const full = slice.slice(0, endIdx)

await kaoruko.sendMessage(targetJid, {
document: Buffer.from(full, 'utf-8'),
mimetype: 'text/plain',
fileName: `${caseName}.js`,
caption: `📦 *${caseName}*•${full.split('\n').length} linhas`
}, { quoted: info })

} catch (e) {
return sendCode(from, '❌ Erro ao buscar case', String(e), 'javascript')
}
break


