if (Number(args[0]) !== 1) return reply(`Tem certeza disso, ${pushname}? Se estiver mesmo disposto/a a terminar com sua dupla, use ${prefix + command} 1`)

const exDupla = getOutherCasal(sender)
breakupAffair(sender)
